# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class CheckoutProcess:
    def __init__(self, cart_items, user_permissions):
        self.cart_items = cart_items
        self.user_permissions = user_permissions

    def validate_cart_items(self):
        # Step 1: Validate cart items
        if not self.cart_items:
            raise ValueError("Cart is empty")
        for item in self.cart_items:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for item {item['name']}")
        return True

    def apply_discount_codes(self, discount_codes):
        # Step 2: Apply discount codes
        total_price = sum(item['price'] * item['quantity'] for item in self.cart_items)
        discount_amount = 0

        for code in discount_codes:
            if code == 'ADMIN_ONLY' and not self.user_permissions.get('admin', False):
                raise PermissionError("Admin-only discount code")
            elif code == 'VIP_ONLY' and not self.user_permissions.get('vip', False):
                raise PermissionError("VIP-only discount code")

            if code == 'SAVE10':
                discount_amount += total_price * 0.10
            elif code == 'SAVE20':
                discount_amount += total_price * 0.20

        return max(0, total_price - discount_amount)

    def calculate_tax(self, subtotal):
        # Step 3: Calculate tax
        tax_rate = 0.08  # Assuming an 8% tax rate
        tax_amount = subtotal * tax_rate
        return subtotal + tax_amount

    def process_payment(self, total_amount):
        # Step 4: Process payment
        # Placeholder for payment processing logic
        if total_amount <= 0:
            raise ValueError("Total amount must be positive")
        print(f"Processing payment of ${total_amount}")
        return True

    def create_order_record(self, total_amount):
        # Step 5: Create order record
        # Placeholder for creating an order record in a database
        order_id = "ORDER12345"
        print(f"Order created with ID {order_id} for ${total_amount}")
        return order_id

    def checkout(self, discount_codes):
        try:
            self.validate_cart_items()
            subtotal = self.apply_discount_codes(discount_codes)
            total_with_tax = self.calculate_tax(subtotal)
            self.process_payment(total_with_tax)
            order_id = self.create_order_record(total_with_tax)
            return order_id
        except Exception as e:
            print(f"Checkout failed: {e}")
            return None

# Example usage
